{ min: 97, max: 98, result: "Veterinarian" },
{ min: 99, max: 100, result: "Wine merchant" }
];

const official = [
    "Arcane university", "Archives", "Asylum", "City hall", "Conservatory",
"Dispensary", "Embassy", "Fire station", "Mayor office",
"Meteorological institute", "Mint", "Palace", "Post office", "School",
"Sewers", "Tax office", "Tourist office", "Tribunal", "University", "Water tower"
];

const religious = [
    "Catacombs", "Cathedral", "Church", "Covent", "Mausoleum", "Monastery",
"Necropolis", "Orphanage", "Sanctuary", "Seminar", "Shrine", "Ziggurat"
];

const publicBuildings = [
    "Aquarium", "Arena", "Art gallery", "Auction hall", "Botanical garden",
"Event center", "Guildhouse", "Gymnasium", "Historical building",
"Hospital", "House for sale", "Library", "Morgue", "Museum", "Observatory",
"Opera", "Public baths", "Theater", "Workshop", "Zoo"
];

const military = [
    "Armory", "Barracks", "Canteen", "Citadel", "Fort", "Guard post",
"Guard tower", "Menagerie", "Military archives", "Military hospital",
"Military school", "Military surplus", "Oubliette", "Prison",
"Recruitment center", "Siege workshop", "Spy academy", "Training hall",
"Underground vault", "Warehouse"
];

const dispositions = [
    { min: 2, max: 2, result: "Attack on sight" },
{ min: 3, max: 5, result: "Hostile" },
{ min: 6, max: 8, result: "Neutral" },
{ min: 9, max: 11, result: "Welcoming" },
{ min: 12, max: 12, result: "Enthusiastic" }
];

const neutralRulerDisposition = [
    "Hostile", "Hostile", "Hostile",
"Welcoming", "Welcoming", "Welcoming"
];

const notableNPCs = [
    "Aggressive guard", "Annoying minstrel", "Bandit in disguise",
"Beggar who knows a lot", "Clever orphan", "Corrupted official",
"Curious waitress", "Distracted scholar", "Haughty nobleman",
"Lonely widow", "Nervous tax collector", "Penniless merchant",
"Princess on the run", "Retired mercenary", "Seasoned adventurer",
"Shady diplomat", "Stubborn wizard", "Talented craftsman",
"Traveler from a distant land", "Vampire/Werewolf hunter"
];

const rulersTable = [
    { min: 1, max: 2, result: "Noble" },
{ min: 3, max: 3, result: "Clergy" },
{ min: 4, max: 4, result: "Council" },
{ min: 5, max: 5, result: "Mayor" },
{ min: 6, max: 6, result: "Merchants’ guild" },
{ min: 7, max: 7, result: "Thieves’ guild" },
{ min: 8, max: 8, result: "Vampire" }
];

const eventTiming = [
    { min: 1, max: 1, result: "Ended earlier" },
{ min: 2, max: 4, result: "Is happening now" },
{ min: 5, max: 6, result: "Will take place in the future" }
];

const cityEvents = [
    "Announcement by a crier", "Assassination", "Ceremony / wedding, etc.",
"Disappearances", "Festival/Fair", "Fire", "Market day", "Plague",
"Siege/Looting", "Tournament", "Vermin invasion",
"Visit of a religious person"
];

// -------------------------
// ROLLS
// -------------------------

let sizeRoll = roll(6);
let sizeData = tableRoll(sizeRoll, citySizeTable);
let citySize = sizeData.size;
let grade = sizeData.grade;
let population = grade * 500;

let occupationRolls = [];
for (let i = 0; i < grade; i++) {
    const r = roll(10);
    occupationRolls.push({ roll: r, result: occupations[r - 1] });
}

let characteristicRolls = uniqueRolls(2, 20);
let characteristicResults = characteristicRolls.map(r => ({
    roll: r,
    result: tableRoll(r, characteristicsTable).result
}));

let appearanceRoll = roll(20);
let appearance = appearances[appearanceRoll - 1];

let colorRoll = null;
let colorScheme = null;

if (appearance === "Specific color scheme") {
    colorRoll = roll(4);
    colorScheme = colorSchemes[colorRoll - 1];
}

let poiRolls = uniqueRolls(grade, 20);
let poiResults = poiRolls.map(r => ({
    roll: r,
    result: pointsOfInterest[r - 1]
}));

function rollBuildingOfInterest() {
    let categoryRoll = roll(20);
    let category = tableRoll(categoryRoll, buildingCategoryTable).result;

    let detailRoll;
    let detailDie;
    let detail;

    if (category === "Housing") {
        detailDie = 20;
        detailRoll = roll(20);
        detail = housing[detailRoll - 1];
    } else if (category === "Business") {
        detailDie = 100;
        detailRoll = roll(100);
        detail = tableRoll(detailRoll, businessTable).result;
    } else if (category === "Official") {
        detailDie = 20;
        detailRoll = roll(20);
        detail = official[detailRoll - 1];
    } else if (category === "Religious") {
        detailDie = 12;
        detailRoll = roll(12);
        detail = religious[detailRoll - 1];
    } else if (category === "Public") {
        detailDie = 20;
        detailRoll = roll(20);
        detail = publicBuildings[detailRoll - 1];
    } else if (category === "Military") {
        detailDie = 20;
        detailRoll = roll(20);
        detail = military[detailRoll - 1];
    }

    return { categoryRoll, category, detailDie, detailRoll, detail };
}

let buildings = [];
for (let i = 0; i < grade * 3; i++) {
    buildings.push(rollBuildingOfInterest());
}

let wallsRoll = roll(100);
let isWalled = wallsRoll <= 50;

let entrances = [];
let entranceCount = grade;

if (isWalled) {
    const directions = ["North", "East", "South", "West"];
    const entranceRolls = uniqueRolls(entranceCount, 4);

    entrances = entranceRolls.map(r => {
        const closureRoll = roll(6);
        let closure = closureRoll <= 3 ? "Wooden doors" : closureRoll <= 5 ? "Portcullis" : "Both";
        return {
            directionRoll: r,
            direction: directions[r - 1],
            closureRoll,
            closure
        };
    });
}

let guardBaseRoll = roll(3);
let guards = (guardBaseRoll + 3) * 5 * grade;

let siegeRoll1 = roll(6);
let siegeRoll2 = roll(6);
let siegeMonths = siegeRoll1 + siegeRoll2;

let dispositionDie1 = roll(6);
let dispositionDie2 = roll(6);
let dispositionTotal = dispositionDie1 + dispositionDie2;
let cityDisposition = tableRoll(dispositionTotal, dispositions).result;

let rulerRoll = roll(8);
let ruler = tableRoll(rulerRoll, rulersTable).result;

let rulerDispositionRoll = roll(6);
let rulerDisposition;

if (cityDisposition === "Neutral") {
    rulerDisposition = neutralRulerDisposition[rulerDispositionRoll - 1];
} else {
    rulerDisposition = rulerDispositionRoll <= 4
    ? `Same as citizens (${cityDisposition})`
    : "Opposite of citizens";
}

let npcRolls = uniqueRolls(grade, 20);
let npcResults = npcRolls.map(r => ({
    roll: r,
    result: notableNPCs[r - 1]
}));

let eventCheckRoll = roll(6);
let hasEvent = eventCheckRoll === 1;

let eventTimingRoll = null;
let eventTime = "None";
let eventRoll = null;
let cityEvent = "None";

if (hasEvent) {
    eventTimingRoll = roll(6);
    eventTime = tableRoll(eventTimingRoll, eventTiming).result;

    eventRoll = roll(12);
    cityEvent = cityEvents[eventRoll - 1];
}

// -------------------------
// OUTPUT
// -------------------------

let output = `
<h2>City Generator</h2>

<h3>Settlement Name</h3>
<p><b>Name:</b> ${settlementName}</p>
<p><b>Format:</b> ${settlementNameFormat}</p>
<ul>
${settlementNameRolls.map(r => `<li>${r}</li>`).join("")}
</ul>

<hr>

<h3>Size</h3>
<p><b>Size Roll:</b> d6 = ${sizeRoll}</p>
<p><b>City Size:</b> ${citySize}</p>
<p><b>Grade:</b> ${grade}</p>
<p><b>Approx. Population:</b> ${population}</p>

<hr>

<h3>Main Occupations</h3>
<p><b>Occupation Rolls:</b> Roll d10 once per grade.</p>
<ul>
${occupationRolls.map(o => `<li>d10 = ${o.roll} → ${o.result}</li>`).join("")}
</ul>

<hr>

<h3>Characteristics</h3>
<p><b>Characteristic Rolls:</b> Roll d20 twice, rerolling duplicates.</p>
<ul>
${characteristicResults.map(c => `<li>d20 = ${c.roll} → ${c.result}</li>`).join("")}
</ul>

<hr>

<h3>Appearance</h3>
<p><b>Appearance Roll:</b> d20 = ${appearanceRoll}</p>
<p><b>Appearance:</b> ${appearance}</p>
${colorScheme ? `<p><b>Color Scheme Roll:</b> d4 = ${colorRoll}</p><p><b>Color Scheme:</b> ${colorScheme}</p>` : ""}

<hr>

<h3>Points of Interest</h3>
<p><b>POI Rolls:</b> Roll d20 once per grade.</p>
<ul>
${poiResults.map(p => `<li>d20 = ${p.roll} → ${p.result}</li>`).join("")}
</ul>

<hr>

<h3>Buildings of Interest</h3>
<p><b>Building Rolls:</b> Roll three times per grade.</p>
<ul>
${buildings.map(b => `
    <li>
    Category Roll: d20 = ${b.categoryRoll} → <b>${b.category}</b><br>
    ${b.category} Roll: d${b.detailDie} = ${b.detailRoll} → <b>${b.detail}</b>
    </li>
    `).join("")}
    </ul>

    <hr>

    <h3>Defense</h3>
    <p><b>Stone Wall Check:</b> d100 = ${wallsRoll}</p>
    <p><b>Walled City:</b> ${isWalled ? "Yes" : "No"}</p>

    ${isWalled ? `
        <p><b>Entrances:</b> ${entranceCount}</p>
        <ul>
        ${entrances.map(e => `
            <li>
            Direction Roll: d4 = ${e.directionRoll} → <b>${e.direction}</b><br>
            Gate Closure Roll: d6 = ${e.closureRoll} → <b>${e.closure}</b>
            </li>
            `).join("")}
            </ul>
            <p><b>Siege Supplies Roll:</b> 2d6 = ${siegeRoll1} + ${siegeRoll2} = ${siegeMonths}</p>
            <p><b>Supplies:</b> Enough food and water for ${siegeMonths} month${siegeMonths === 1 ? "" : "s"}.</p>
            ` : ""}

            <p><b>Guard Roll:</b> (d3 + 3) × 5 × grade = (${guardBaseRoll} + 3) × 5 × ${grade}</p>
            <p><b>Guards:</b> ${guards}</p>

            <hr>

            <h3>People</h3>
            <p><b>Citizen Disposition Roll:</b> 2d6 = ${dispositionDie1} + ${dispositionDie2} = ${dispositionTotal}</p>
            <p><b>Citizen Disposition:</b> ${cityDisposition}</p>

            <p><b>Ruler Roll:</b> d8 = ${rulerRoll}</p>
            <p><b>Ruler:</b> ${ruler}</p>

            <p><b>Ruler Disposition Roll:</b> d6 = ${rulerDispositionRoll}</p>
            <p><b>Ruler Disposition:</b> ${rulerDisposition}</p>

            <h4>Notable NPCs</h4>
            <ul>
            ${npcResults.map(n => `<li>d20 = ${n.roll} → ${n.result}</li>`).join("")}
            </ul>

            <hr>

            <h3>Event</h3>
            <p><b>Event Check:</b> d6 = ${eventCheckRoll}</p>
            <p><b>Has Event:</b> ${hasEvent ? "Yes" : "No"}</p>
            ${hasEvent ? `
                <p><b>Event Timing Roll:</b> d6 = ${eventTimingRoll}</p>
                <p><b>Timing:</b> ${eventTime}</p>
                <p><b>Event Roll:</b> d12 = ${eventRoll}</p>
                <p><b>Event:</b> ${cityEvent}</p>
                ` : `<p><b>Event:</b> None</p>`}

                <hr>

                <h3>Quick Summary</h3>
                <p>
                <b>${settlementName}</b> is a <b>${citySize.toLowerCase()}</b> city of about
                <b>${population}</b> people. Its main occupations include
                <b>${occupationRolls.map(o => o.result.toLowerCase()).join(", ")}</b>.
                The city is known for: <b>${characteristicResults.map(c => c.result.toLowerCase()).join(", ")}</b>.
                Its appearance is <b>${appearance.toLowerCase()}</b>${colorScheme ? ` with a <b>${colorScheme.toLowerCase()}</b> color scheme` : ""}.
                The citizens are <b>${cityDisposition.toLowerCase()}</b>, and the city is ruled by <b>${ruler.toLowerCase()}</b>.
                ${isWalled ? `It is protected by stone walls with <b>${entranceCount}</b> entrance${entranceCount === 1 ? "" : "s"}.` : "It is not enclosed by stone walls."}
                ${hasEvent ? ` Current event: <b>${cityEvent}</b> — ${eventTime.toLowerCase()}.` : ""}
                </p>
                `;

                if (globalThis.currentHexFaction) {
                    output += `
                    <hr>

                    <h3>Faction</h3>

                    <p><b>Controlling Faction:</b></p>
                    <p>${globalThis.currentHexFaction}</p>
                    `;
                }

                ChatMessage.create({
                    speaker: ChatMessage.getSpeaker(),
                                   content: output
                });
